RED.sidebar.meo = (function() {
    var content;
    var mainView;
    var formView;
    var profileListContainer;

    function getApiUrl() {
        return RED.settings.theme("meo.apiUrl") || "http://localhost:7070";
    }

    function init() {
        content = $('<div id="red-ui-sidebar-meo"></div>');

        // ── Main view ──────────────────────────────────────────────
        mainView = $('<div class="meo-main-view"></div>').appendTo(content);

        // Device Profiles section
        var profileSection = $('<div class="meo-section"></div>').appendTo(mainView);
        var profileHeader = $('<div class="meo-section-header"></div>').appendTo(profileSection);
        $('<span class="meo-section-title">Device Profiles</span>').appendTo(profileHeader);
        var btnGroup = $('<div class="meo-btn-group"></div>').appendTo(profileHeader);
        $('<button class="red-ui-button red-ui-button-small" title="Refresh"><i class="fa fa-refresh"></i></button>')
            .appendTo(btnGroup)
            .on('click', refresh);
        $('<button class="red-ui-button red-ui-button-small" title="Add Profile"><i class="fa fa-plus"></i></button>')
            .appendTo(btnGroup)
            .on('click', function() { showProfileForm(null); });
        profileListContainer = $('<div class="meo-list-container"></div>').appendTo(profileSection);

        // Devices section (placeholder until /api/v1/devices is implemented)
        var deviceSection = $('<div class="meo-section"></div>').appendTo(mainView);
        $('<div class="meo-section-header"><span class="meo-section-title">Devices</span></div>').appendTo(deviceSection);
        $('<div class="meo-empty-note">Device list not yet available.</div>').appendTo(deviceSection);

        // ── Form view (hidden by default) ──────────────────────────
        formView = $('<div class="meo-form-view"></div>').hide().appendTo(content);

        RED.sidebar.addTab({
            id: "meo",
            label: "MEO",
            name: "MEO Dashboard",
            iconClass: "fa fa-tachometer",
            content: content,
            pinned: true,
            enableOnEdit: false,
            onchange: refresh
        });
    }

    // ── List ───────────────────────────────────────────────────────

    function refresh() {
        profileListContainer.html('<div class="meo-loading"><i class="fa fa-spinner fa-spin"></i> Loading…</div>');
        $.ajax({
            url: getApiUrl() + "/api/v1/device-profiles",
            method: "GET",
            dataType: "json",
            success: renderProfileList,
            error: function() {
                profileListContainer.html(
                    '<div class="meo-error"><i class="fa fa-exclamation-triangle"></i> ' +
                    'Cannot reach MEO API. Set <code>editorTheme.meo.apiUrl</code> in settings.js.</div>'
                );
            }
        });
    }

    function renderProfileList(profiles) {
        profileListContainer.empty();
        if (!profiles || profiles.length === 0) {
            $('<div class="meo-empty-note">No device profiles. Click <i class="fa fa-plus"></i> to create one.</div>')
                .appendTo(profileListContainer);
            return;
        }
        profiles.forEach(function(profile) {
            var item = $('<div class="meo-profile-item"></div>').appendTo(profileListContainer);
            var info = $('<div class="meo-profile-info"></div>').appendTo(item);
            $('<div class="meo-profile-name"></div>').text(profile.name).appendTo(info);
            var capCount = profile.capabilities ? profile.capabilities.length : 0;
            $('<div class="meo-profile-meta"></div>')
                .text(profile.profileId + ' · v' + profile.version + ' · ' + capCount + ' capability' + (capCount !== 1 ? 's' : ''))
                .appendTo(info);
            var actions = $('<div class="meo-profile-actions"></div>').appendTo(item);
            $('<button class="red-ui-button red-ui-button-small" title="Edit"><i class="fa fa-pencil"></i></button>')
                .appendTo(actions)
                .on('click', function() { showProfileForm(profile); });
            $('<button class="red-ui-button red-ui-button-small meo-btn-danger" title="Delete"><i class="fa fa-trash"></i></button>')
                .appendTo(actions)
                .on('click', function() { confirmDeleteProfile(profile.profileId, profile.name); });
        });
    }

    // ── Form ───────────────────────────────────────────────────────

    function showProfileForm(profile) {
        var isNew = !profile;
        // Deep-clone so edits don't mutate the displayed list until saved
        var editProfile = isNew
            ? { profileId: '', name: '', description: '', version: 1, capabilities: [] }
            : JSON.parse(JSON.stringify(profile));

        mainView.hide();
        formView.empty().show();

        var formHeader = $('<div class="meo-form-header"></div>').appendTo(formView);
        $('<button class="red-ui-button red-ui-button-small" title="Back"><i class="fa fa-arrow-left"></i></button>')
            .appendTo(formHeader)
            .on('click', hideForm);
        $('<span class="meo-section-title"></span>')
            .text(isNew ? 'Add Device Profile' : 'Edit: ' + profile.name)
            .appendTo(formHeader);

        var formBody = $('<div class="meo-form-body"></div>').appendTo(formView);
        buildProfileForm(formBody, editProfile, isNew);

        var formFooter = $('<div class="meo-form-footer"></div>').appendTo(formView);
        $('<button class="red-ui-button primary">Save</button>')
            .appendTo(formFooter)
            .on('click', function() { saveProfile(editProfile, isNew); });
        $('<button class="red-ui-button">Cancel</button>')
            .appendTo(formFooter)
            .on('click', hideForm);
    }

    function hideForm() {
        formView.hide();
        mainView.show();
    }

    function buildProfileForm(container, profile, isNew) {
        function row(label, input) {
            var r = $('<div class="form-row"></div>').appendTo(container);
            $('<label></label>').text(label).appendTo(r);
            input.appendTo(r);
        }

        var idInput = $('<input type="text" class="red-ui-typedInput" placeholder="e.g. meo-sensor-v1">')
            .val(profile.profileId);
        if (!isNew) { idInput.prop('disabled', true); }
        idInput.on('input', function() { profile.profileId = $(this).val().trim(); });
        row('Profile ID', idInput);

        var nameInput = $('<input type="text" class="red-ui-typedInput" placeholder="Display name">')
            .val(profile.name)
            .on('input', function() { profile.name = $(this).val(); });
        row('Name', nameInput);

        var descInput = $('<input type="text" class="red-ui-typedInput" placeholder="Optional">')
            .val(profile.description || '')
            .on('input', function() { profile.description = $(this).val(); });
        row('Description', descInput);

        var verInput = $('<input type="number" min="1" class="red-ui-typedInput">')
            .val(profile.version || 1)
            .on('input', function() { profile.version = parseInt($(this).val()) || 1; });
        row('Version', verInput);

        $('<div class="meo-subsection-title">Capabilities</div>').appendTo(container);
        var capContainer = $('<div class="meo-cap-list"></div>').appendTo(container);

        (profile.capabilities || []).forEach(function(cap) {
            appendCapRow(capContainer, cap, profile);
        });

        $('<button class="red-ui-button" style="margin-top:6px;"><i class="fa fa-plus"></i> Add Capability</button>')
            .appendTo(container)
            .on('click', function() {
                var nextId = (profile.capabilities || []).reduce(function(m, c) {
                    return Math.max(m, c.capabilityId || 0);
                }, 0) + 1;
                var newCap = { capabilityId: nextId, name: '', permission: 7, unit: '', valueType: '' };
                if (!profile.capabilities) { profile.capabilities = []; }
                profile.capabilities.push(newCap);
                appendCapRow(capContainer, newCap, profile);
            });
    }

    function appendCapRow(container, cap, profile) {
        var row = $('<div class="meo-cap-row"></div>').appendTo(container);
        $('<input type="number" min="1" class="red-ui-typedInput meo-cap-id" title="Capability ID" placeholder="ID">')
            .val(cap.capabilityId)
            .appendTo(row)
            .on('input', function() { cap.capabilityId = parseInt($(this).val()) || 0; });
        $('<input type="text" class="red-ui-typedInput meo-cap-name" title="Name" placeholder="Name">')
            .val(cap.name)
            .appendTo(row)
            .on('input', function() { cap.name = $(this).val(); });
        $('<input type="text" class="red-ui-typedInput meo-cap-unit" title="Unit" placeholder="Unit">')
            .val(cap.unit || '')
            .appendTo(row)
            .on('input', function() { cap.unit = $(this).val(); });
        $('<button class="red-ui-button red-ui-button-small meo-btn-danger" title="Remove"><i class="fa fa-times"></i></button>')
            .appendTo(row)
            .on('click', function() {
                var idx = profile.capabilities.indexOf(cap);
                if (idx !== -1) { profile.capabilities.splice(idx, 1); }
                row.remove();
            });
    }

    function saveProfile(profile, isNew) {
        if (!profile.profileId) { RED.notify('Profile ID is required', 'error'); return; }
        if (!profile.name)      { RED.notify('Name is required', 'error'); return; }
        if ((profile.version || 0) < 1) { RED.notify('Version must be ≥ 1', 'error'); return; }

        var method = isNew ? "POST" : "PUT";
        var url = getApiUrl() + "/api/v1/device-profiles" +
            (isNew ? "" : "/" + encodeURIComponent(profile.profileId));

        $.ajax({
            url: url,
            method: method,
            contentType: "application/json",
            data: JSON.stringify(profile),
            success: function() {
                hideForm();
                refresh();
                RED.notify('Profile ' + (isNew ? 'created' : 'updated'), 'success');
            },
            error: function(xhr) {
                var msg = 'Failed to save profile';
                try { msg = JSON.parse(xhr.responseText).error || msg; } catch(e) {}
                RED.notify(msg, 'error');
            }
        });
    }

    function confirmDeleteProfile(profileId, name) {
        var dialog = RED.popover.dialog({
            title: 'Delete Profile',
            content: $('<p></p>').text('Delete "' + name + '"? This cannot be undone.'),
            buttons: [
                {
                    text: 'Cancel',
                    click: function() { dialog.close(); }
                },
                {
                    text: 'Delete',
                    class: 'primary',
                    click: function() {
                        dialog.close();
                        deleteProfile(profileId);
                    }
                }
            ]
        });
    }

    function deleteProfile(profileId) {
        $.ajax({
            url: getApiUrl() + "/api/v1/device-profiles/" + encodeURIComponent(profileId),
            method: "DELETE",
            success: function() {
                refresh();
                RED.notify('Profile deleted', 'success');
            },
            error: function() {
                RED.notify('Failed to delete profile', 'error');
            }
        });
    }

    return {
        init: init,
        refresh: refresh
    };
})();
